-- アボカド品種データ
-- Supabase SQL Editorで実行してください。
-- public_notes には出典を入れていません。

insert into public.fruits (
  name_ja,
  name_en,
  slug,
  scientific_name,
  family_name,
  origin,
  description,
  cultivation_summary,
  okinawa_suitability,
  is_public
) values (
  'アボカド',
  'Avocado',
  'avocado',
  'Persea americana',
  'クスノキ科',
  '中南米',
  'クリーミーな果肉を食べる常緑果樹です。',
  'A型・B型の開花型、排水、風対策、収穫時期を見ながら品種を組み合わせます。',
  '沖縄では耐寒性よりも排水性、台風対策、高温多湿期の管理が重要です。',
  true
) on conflict (slug) do update set
  name_ja = excluded.name_ja,
  name_en = excluded.name_en,
  scientific_name = excluded.scientific_name,
  family_name = excluded.family_name,
  origin = excluded.origin,
  description = excluded.description,
  cultivation_summary = excluded.cultivation_summary,
  okinawa_suitability = excluded.okinawa_suitability,
  is_public = true,
  updated_at = now();

with avocado as (
  select id from public.fruits where slug = 'avocado'
),
source (name_ja, name_en, slug, origin, description, fruit_size, taste, texture, aroma, harvest_season, tree_vigor, difficulty, okinawa_suitability, container_suitability, beginner_suitability, kenyu_comment, public_notes, is_public) as (
