insert into public.cultivars (
  fruit_id,
  name_ja,
  name_en,
  slug,
  origin,
  description,
  fruit_size,
  taste,
  texture,
  aroma,
  harvest_season,
  tree_vigor,
  difficulty,
  okinawa_suitability,
  container_suitability,
  beginner_suitability,
  kenyu_comment,
  public_notes,
  is_public
)
select
  avocado.id,
  source.name_ja,
  source.name_en,
  source.slug,
  source.origin,
  source.description,
  source.fruit_size,
  source.taste,
  source.texture,
  source.aroma,
  source.harvest_season,
  source.tree_vigor,
  source.difficulty,
  source.okinawa_suitability,
  source.container_suitability,
  source.beginner_suitability,
  source.kenyu_comment,
  source.public_notes,
  source.is_public
from source
cross join avocado
on conflict (fruit_id, slug) do update set
  name_ja = excluded.name_ja,
  name_en = excluded.name_en,
  origin = excluded.origin,
  description = excluded.description,
  fruit_size = excluded.fruit_size,
  taste = excluded.taste,
  texture = excluded.texture,
  aroma = excluded.aroma,
  harvest_season = excluded.harvest_season,
  tree_vigor = excluded.tree_vigor,
  difficulty = excluded.difficulty,
  okinawa_suitability = excluded.okinawa_suitability,
  container_suitability = excluded.container_suitability,
  beginner_suitability = excluded.beginner_suitability,
  kenyu_comment = excluded.kenyu_comment,
  public_notes = excluded.public_notes,
  is_public = true,
  updated_at = now();

select
  count(*) as avocado_cultivar_count
from public.cultivars
join public.fruits on fruits.id = cultivars.fruit_id
where fruits.slug = 'avocado';
